form:Form.form:Scripts:
		var valorInicial;
function LoadForm()
{	  
	CargarFecha();     
  	clickLista();   
  	if(Ctrl('main').GetMode()=="EDIT")
    	valorInicial = Ctrl('l_publicar').GetXValue();    

	if (Ctrl('main').GetMode()=="SHOW" || Ctrl('main').GetMode()=="LIST")
    {

  	  	CtrlEnabled('EDIT',(Ctrl('c_estado').GetXValue() == "C" || Ctrl('c_estado').GetXValue() == "F") ? false:true);

    	//Publicado
    	if (Ctrl('c_estado').GetXValue() == "P")
    	{
     		CtrlEnabled('PUBLICADO',false);
			CtrlEnabled('RECLUTANDO',true);
			CtrlEnabled('CANCELADO',true);
			CtrlEnabled('FINALIZADO',false);
    	}
    	//Reclutado
    	if (Ctrl('c_estado').GetXValue() == "R")
    	{
      		CtrlEnabled('PUBLICADO',false);
			CtrlEnabled('RECLUTANDO',false);
			CtrlEnabled('CANCELADO',false);
			CtrlEnabled('FINALIZADO',true);
    	}
    	//Cancelado
    	if (Ctrl('c_estado').GetXValue() == "C")
    	{
    		CtrlEnabled('PUBLICADO',true);
			CtrlEnabled('RECLUTANDO',false);
			CtrlEnabled('CANCELADO',false);
			CtrlEnabled('FINALIZADO',false);
    	}                          
    	//finalizado
    	if (Ctrl('c_estado').GetXValue() == "F")
    	{
    		CtrlEnabled('PUBLICADO',false); 
			CtrlEnabled('RECLUTANDO',false);
			CtrlEnabled('CANCELADO',false);
			CtrlEnabled('FINALIZADO',false);
    	}
  	}

  	if (Ctrl('f_hoy'))
            Ctrl('f_hoy').SetXValue(date2str(new Date())); 
}

function ReclutarAviso()
{ 
	Ctrl("f_estado_hid").SetXValue(datetime2str(new Date()));

	Ctrl("main").DoEvent("SetReclutar");                  	
}
function PublicarAviso()
{    
    Ctrl("f_estado_hid").SetXValue(datetime2str(new Date()));

    CtrlEnabled('f_cierre',true);

    Ctrl("f_cierre").SetXValue('');

    CtrlEnabled('f_cierre',false);

    Ctrl("main").DoEvent("SetPublicar");                  
}   
function CancelarAviso()
{
    Ctrl("f_estado_hid").SetXValue(datetime2str(new Date()));

    CtrlEnabled('f_cierre',true);

    Ctrl("f_cierre").SetXValue(datetime2str(new Date()));

    CtrlEnabled('f_cierre',false);

    Ctrl("main").DoEvent("SetCancel");                      
}   
function FinalizarAviso()
{
    Ctrl("f_estado_hid").SetXValue(datetime2str(new Date()));  

    CtrlEnabled('f_cierre',true);

    Ctrl("f_cierre").SetXValue(datetime2str(new Date()));

    CtrlEnabled('f_cierre',false);

    Ctrl("main").DoEvent("SetFinal");                  
}



function validarCerrada(myThis)
{
 if (Ctrl('main').GetMode() == "SHOW")
 {
	 if (Ctrl('f_cierre').TypedValue() < new Date() && Ctrl('f_cierre').GetXValue() != "" )
	 {
	   alert('No puede modificar un aviso cerrado.');
	   return false;
	 } 
 } 
 return true;
}              

function val_mail(me)
{
	if((Ctrl('main').getmode = "NEW") || (Ctrl('main').getmode = "EDIT"))
	{
		var mail = me.GetXValue();    	
		if (mail.length!= 0)
		{				
			if (mail.split("@").length != 2)
			{
				me.SetError("El mail es inválido");
				return false;
			}
			var array_mail = mail.split("@")
			if (array_mail[1].indexOf(".") < 0)
			{
				me.SetError("El mail es inválido");
				return false;
			}
			/* Verificar la existencia de caracteres. ( ) < > @ , ; : \ " . [ ] */
			var specialChars="\\(\\)<>@,;:\\\\\\\"\\.\\[\\]";
			var validChars="\[^\\s" + specialChars + "\]";
			var quotedUser="(\"[^\"]*\")";
			var atom=validChars + '+';
			var word="(" + atom + "|" + quotedUser + ")";
			var userPat=new RegExp("^" + word + "(\\." + word + ")*$");

			if (array_mail[0].match(userPat)==null)
			{
				me.SetError("El mail es inválido");
				return false;
			}
			if (array_mail[1].match(userPat)==null)
			{
				me.SetError("El mail es inválido");
				return false;
			}
			return true;
	  } 
	  else
	  	{
	  	return true;
	  	}
  }

}      
function SetAvisoValues()
{
	if(Ctrl("oi_puesto").GetCValue()!="")
	{
		var datos = Ctrl("oi_puesto").GetCValue().split(' - ');
			//datos[0] = codigo
			//datos[1] = descripcion  
		if (Ctrl('main').GetMode() == "EDIT" || Ctrl('main').GetMode() == "NEW" )		
		{
		 Ctrl("d_puesto").SetCValue(datos[1]);
		}	
		var puesto;				
		np = new NomadProxy("", ut);
		var nSQL = np.SQLService();
		puesto = nSQL.GetOBJ(Ctrl("main").getResource("QRY_PUESTO"), "<PARAM oi_puesto=\""+Ctrl("oi_puesto").GetXValue()+"\" />"); 		

		if (puesto.l_usa_plantilla==1)
		{
			if(puesto.o_puesto)
				Ctrl("o_aviso").SetCValue(puesto.o_puesto); 		
			if(puesto.oi_jerarquia)
				Ctrl("oi_jerarquia").SetXValue(puesto.oi_jerarquia); 
			if(puesto.oi_area)	
				Ctrl("oi_area").SetXValue(puesto.oi_area);
			if(puesto.oi_tipo_jor_lab)	
				Ctrl("oi_tipo_jor_lab").SetXValue(puesto.oi_tipo_jor_lab);
			if(puesto.l_vehiculo)	
				Ctrl("l_vehiculo").SetCValue(puesto.l_vehiculo);
			if(puesto.c_viajar)	
				Ctrl("c_viajar").SetCValue(puesto.c_viajar);
			if(puesto.c_radicarse)	
				Ctrl("c_radicarse").SetCValue(puesto.c_radicarse);
			if(puesto.l_lic_conduc)	
				Ctrl("l_lic_conduc").SetCValue(puesto.l_lic_conduc);			
			if(puesto.c_sexo)
				Ctrl("c_sexo").SetXValue(puesto.c_sexo);
			if(puesto.d_mail)
				Ctrl("d_mail").SetCValue(puesto.d_mail); 
			if(puesto.d_mail_alt_1)
				Ctrl("d_mail_alt_1").SetCValue(puesto.d_mail_alt_1); 
			if(puesto.d_mail_alt_2)
				Ctrl("d_mail_alt_2").SetCValue(puesto.d_mail_alt_2); 
			if(puesto.oi_pais)
				Ctrl("oi_pais").SetXValue(puesto.oi_pais); 
			if(puesto.oi_provincia)
				Ctrl("oi_provincia").SetXValue(puesto.oi_provincia); 
			if(puesto.oi_localidad)
				Ctrl("oi_localidad").SetXValue(puesto.oi_localidad); 		

				Ctrl("f_estado_hid").SetXValue(datetime2str(new Date()));		                                                     		
		}
		else
		{
			clearCampos();
		}
	}
	else
	{
		Ctrl("d_puesto").SetCValue("");
		clearCampos();
	}
}

function clearCampos()
{
	Ctrl("oi_jerarquia").SetXValue(""); 
	Ctrl("oi_area").SetXValue("");
	Ctrl("c_sexo").SetCValue("");
	Ctrl("l_lic_conduc").SetCValue("");
	Ctrl("oi_tipo_jor_lab").SetCValue("");
	Ctrl("c_viajar").SetCValue("");
	Ctrl("c_radicarse").SetCValue("");
	Ctrl("l_vehiculo").SetCValue("");
	Ctrl("d_mail").SetCValue(""); 
	Ctrl("d_mail_alt_1").SetCValue(""); 
	Ctrl("d_mail_alt_2").SetCValue(""); 
	Ctrl("oi_pais").SetXValue(""); 
	Ctrl("oi_provincia").SetXValue(""); 
	Ctrl("oi_localidad").SetXValue(""); 
	Ctrl("o_aviso").SetCValue(""); 	
}
function clickLista()
{
  if (Ctrl('main').GetMode() == 'LIST') 
	{ 
	  if(Ctrl('LIST').GetSelectAttrValue('c_estado') == 'P')
		{	
			CtrlEnabled('PUBLICADO',false);
			CtrlEnabled('RECLUTANDO',true);
			CtrlEnabled('CANCELADO',true);
			CtrlEnabled('FINALIZADO',false);	
		}	
		if(Ctrl('LIST').GetSelectAttrValue('c_estado') == 'R')
		{	
			CtrlEnabled('PUBLICADO',false);
			CtrlEnabled('RECLUTANDO',false);
			CtrlEnabled('CANCELADO',false);
			CtrlEnabled('FINALIZADO',true);
		}	                              
		if(Ctrl('LIST').GetSelectAttrValue('c_estado') == 'C')
		{	
			CtrlEnabled('PUBLICADO',true);
			CtrlEnabled('RECLUTANDO',false);
			CtrlEnabled('CANCELADO',false);
			CtrlEnabled('FINALIZADO',false);	
		}	
		if(Ctrl('LIST').GetSelectAttrValue('c_estado') == 'F')
		{	
			CtrlEnabled('PUBLICADO',false); 
			CtrlEnabled('RECLUTANDO',false);
			CtrlEnabled('CANCELADO',false);
			CtrlEnabled('FINALIZADO',false);
		}
	}  

}

function Save()
{                       
	var grid = Ctrl('grid');
    var arrTag = Ctrl('arrTag');

	for (var i=0; i<grid.TotalRowsCount(); i++)
	{
	  	valor = grid.GetCellXValue('value', i );    
	   	row = arrTag.GetRow(i);
	   	codigo = row.GetAttr("codigo")
	   	Ctrl(codigo).SetXValue(valor); 	
	}	

	return true;
}          

        function CargarFecha()
{                               
	if (Ctrl('main').GetMode() != "LIST")
	{
		if (Ctrl('f_aviso') != null && Ctrl('f_aviso').GetCValue() == "")
			{                                         
				Ctrl('f_aviso').SetTypedValue(new Date());
			}
		CtrlEnabled('f_aviso', true); 
	}
	Ctrl("f_estado_hid").SetXValue(datetime2str(new Date()));//////////GUARDO FECHA ESTADO
}        

function Publicar(me)
{  

	if (Ctrl('main').GetMode() == "EDIT" && me.GetXValue() == "0" && valorInicial != me.GetXValue())
	{
  		Ctrl('f_cierre').SetXValue(datetime2str(new Date()));
  		CtrlEnabled("f_cierre",false);     
	}
	else   
	{  
		Ctrl('f_cierre').SetXValue("");
	    CtrlEnabled("f_cierre",true);          
	}
}                               

function cambiaDispo(e)
{       
    estado = e.GetXValue();
    Ctrl('l_full_time').SetXValue('0');
    Ctrl('l_part_time').SetXValue('0');
    Ctrl('l_temporal').SetXValue('0');
    Ctrl('l_remoto').SetXValue('0');     

    e.SetXValue(estado);
}
